UPDATE 
    user_campaign 
SET 
    Status = #{statusValue} 
WHERE 
    campaign_id = #{campaignId} 
AND 
    user_no = #{userNo}
AND
    apply_date = #{applyDate}
AND
    is_deleted = 'N'

